            id = id,
            title = title,
            description = description,
            source = Source.valueOf(source),
            category = Category.valueOf(category),
            url = url,
            stars = stars,
            author = author,
            tags = try {
                json.decodeFromString(tags)
            } catch (e: Exception) {
