                    ignoreUnknownKeys = true
                    isLenient = true
                })
            }
            install(Logging) {
                level = LogLevel.INFO
            }
            engine {
                connectTimeout = 30_000
                socketTimeout = 30_000
            }
        }
    }

    @Provides
    @Singleton
    fun provideGitHubApi(client: HttpClient): GitHubApi {
        return GitHubApi(client)
    }

    @Provides
    @Singleton
    fun provideHotspotRepository(
        impl: HotspotRepositoryImpl
    ): IHotspotRepository = impl
}

