/**
 * 热点卡片 - 宋代美学设计
 */
@Composable
fun HotspotCard(
    hotspot: Hotspot,
    onClick: () -> Unit,
    onBookmarkClick: () -> Unit,
    modifier: Modifier = Modifier
) {
    Card(
        onClick = onClick,
        modifier = modifier.fillMaxWidth(),
        shape = RoundedCornerShape(12.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface
        ),
        elevation = CardDefaults.cardElevation(
            defaultElevation = 1.dp
        )
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
        ) {
            // 顶部：来源标签 + 时间
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                SourceChip(source = hotspot.source)

                Row(verticalAlignment = Alignment.CenterVertically) {
                    if (hotspot.isBookmarked) {
                        Icon(
                            imageVector = Icons.Filled.Bookmark,
                            contentDescription = "已收藏",
                            tint = GoldLeaf,
                            modifier = Modifier.size(16.dp)
                        )
                        Spacer(modifier = Modifier.width(4.dp))
                    }

                    Text(
                        text = formatRelativeTime(hotspot.publishedAt),
                        style = MaterialTheme.typography.labelSmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            // 标题
            Text(
                text = hotspot.title,
                style = MaterialTheme.typography.titleMedium,
                color = MaterialTheme.colorScheme.onSurface,
                maxLines = 2,
                overflow = TextOverflow.Ellipsis
            )

            // 描述（如果有）
            if (hotspot.description.isNotEmpty()) {
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = hotspot.description,
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant,
                    maxLines = 2,
                    overflow = TextOverflow.Ellipsis
                )
            }

            // 底部：标签 + 操作
            Spacer(modifier = Modifier.height(12.dp))

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                // 分类和标签
                Row(
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    CategoryChip(category = hotspot.category)

                    if (hotspot.stars != null && hotspot.stars > 0) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(
                                imageVector = Icons.Filled.Star,
                                contentDescription = "Stars",
                                tint = GoldLeaf,
                                modifier = Modifier.size(14.dp)
                            )
                            Spacer(modifier = Modifier.width(2.dp))
                            Text(
                                text = formatStars(hotspot.stars),
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    }
                }

                // 收藏按钮
                IconButton(
                    onClick = onBookmarkClick,
                    modifier = Modifier.size(36.dp)
                ) {
                    Icon(
                        imageVector = if (hotspot.isBookmarked) {
                            Icons.Filled.Bookmark
                        } else {
                            Icons.Outlined.BookmarkBorder
                        },
                        contentDescription = if (hotspot.isBookmarked) "取消收藏" else "收藏",
                        tint = if (hotspot.isBookmarked) {
                            GoldLeaf
                        } else {
                            MaterialTheme.colorScheme.onSurfaceVariant
                        }
                    )
                }
            }
        }
    }
}

@Composable
fun SourceChip(source: Source) {
    val backgroundColor = when (source) {
        Source.GITHUB -> SourceGithub
        Source.WAYTOAGI -> SourceWaytoAGI
        Source.RSS -> SourceRSS
        Source.OTHER -> SourceOther
    }

    Surface(
        shape = RoundedCornerShape(4.dp),
        color = backgroundColor
    ) {
        Text(
            text = source.displayName,
            style = MaterialTheme.typography.labelSmall,
            color = androidx.compose.ui.graphics.Color.White,
            modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
        )
    }
}

@Composable
fun CategoryChip(category: Category) {
    val backgroundColor = when (category) {
        Category.PROJECT -> CategoryProject
        Category.TOOL -> CategoryTool
        Category.MODEL -> CategoryModel
        Category.NEWS -> CategoryNews
        Category.TUTORIAL -> CategoryTutorial
        Category.AGENT -> CeladonPrimary
        Category.FRAMEWORK -> CategoryTool
        Category.OTHER -> SourceOther
    }

    Surface(
        shape = RoundedCornerShape(4.dp),
        color = backgroundColor.copy(alpha = 0.15f)
    ) {
        Text(
            text = category.displayName,
            style = MaterialTheme.typography.labelSmall,
            color = backgroundColor,
            modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
        )
    }
}

// 格式化相对时间
@Composable
fun formatRelativeTime(dateTime: java.time.LocalDateTime): String {
    val now = java.time.LocalDateTime.now()
    val diff = java.time.Duration.between(dateTime, now)

    return when {
        diff.toMinutes() < 1 -> "刚刚"
        diff.toMinutes() < 60 -> "${diff.toMinutes()}分钟前"
        diff.toHours() < 24 -> "${diff.toHours()}小时前"
        diff.toDays() < 7 -> "${diff.toDays()}天前"
        else -> {
            val formatter = java.time.format.DateTimeFormatter.ofPattern("MM-dd")
            dateTime.format(formatter)
        }
    }
}

// 格式化Star数量
fun formatStars(stars: Int): String {
    return when {
        stars >= 1000000 -> String.format("%.1fM", stars / 1000000.0)
        stars >= 1000 -> String.format("%.1fK", stars / 1000.0)
        else -> stars.toString()
    }
}

