            modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
        )
    }
}

@Composable
fun CategoryChip(category: Category) {
    val backgroundColor = when (category) {
        Category.PROJECT -> CategoryProject
        Category.TOOL -> CategoryTool
        Category.MODEL -> CategoryModel
        Category.NEWS -> CategoryNews
        Category.TUTORIAL -> CategoryTutorial
        Category.AGENT -> CeladonPrimary
        Category.FRAMEWORK -> CategoryTool
        Category.OTHER -> SourceOther
    }

    Surface(
        shape = RoundedCornerShape(4.dp),
        color = backgroundColor.copy(alpha = 0.15f)
    ) {
        Text(
            text = category.displayName,
            style = MaterialTheme.typography.labelSmall,
            color = backgroundColor,
            modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
        )
    }
}

// 格式化相对时间
@Composable
fun formatRelativeTime(dateTime: java.time.LocalDateTime): String {
    val now = java.time.LocalDateTime.now()
    val diff = java.time.Duration.between(dateTime, now)

    return when {
        diff.toMinutes() < 1 -> "刚刚"
        diff.toMinutes() < 60 -> "${diff.toMinutes()}分钟前"
        diff.toHours() < 24 -> "${diff.toHours()}小时前"
        diff.toDays() < 7 -> "${diff.toDays()}天前"
        else -> {
            val formatter = java.time.format.DateTimeFormatter.ofPattern("MM-dd")
            dateTime.format(formatter)
        }
    }
}

// 格式化Star数量
fun formatStars(stars: Int): String {
    return when {
        stars >= 1000000 -> String.format("%.1fM", stars / 1000000.0)
        stars >= 1000 -> String.format("%.1fK", stars / 1000.0)
        else -> stars.toString()
    }
}

