@HiltViewModel
class SettingsViewModel @Inject constructor(
    @ApplicationContext private val context: Context
) : ViewModel() {

    private val _state = MutableStateFlow(SettingsState())
    val state = _state.asStateFlow()

    private val json = Json { ignoreUnknownKeys = true }

    init {
        loadSettings()
    }

    private fun loadSettings() {
        viewModelScope.launch {
            // 加载主题设置
            val themeName = context.settingsDataStore.data.map { prefs ->
                prefs[stringPreferencesKey("app_theme")] ?: AppTheme.LIGHT.name
            }.first()

            val theme = try {
                AppTheme.valueOf(themeName)
            } catch (e: Exception) {
                AppTheme.LIGHT
            }

            // 加载自动刷新设置
            val autoRefresh = context.settingsDataStore.data.map { prefs ->
                prefs[booleanPreferencesKey("auto_refresh")] ?: true
            }.first()

            val refreshInterval = context.settingsDataStore.data.map { prefs ->
                prefs[intPreferencesKey("refresh_interval")] ?: 6
            }.first()

            val notificationEnabled = context.settingsDataStore.data.map { prefs ->
                prefs[booleanPreferencesKey("notification_enabled")] ?: true
            }.first()

            // 加载LLM配置
            val llmConfigsJson = context.settingsDataStore.data.map { prefs ->
                prefs[stringPreferencesKey("llm_configs")] ?: "{}"
            }.first()

            val llmConfigs = try {
                json.decodeFromString<Map<String, LLMConfig>>(llmConfigsJson)
                    .mapKeys { LLMProvider.valueOf(it.key) }
            } catch (e: Exception) {
                emptyMap()
            }

            _state.update {
                it.copy(
                    currentTheme = theme,
                    autoRefreshEnabled = autoRefresh,
                    refreshIntervalHours = refreshInterval,
                    notificationEnabled = notificationEnabled,
                    llmConfigs = llmConfigs
                )
            }
        }
    }

    fun setTheme(theme: AppTheme) {
        viewModelScope.launch {
            context.settingsDataStore.edit { prefs ->
                prefs[stringPreferencesKey("app_theme")] = theme.name
            }
            _state.update { it.copy(currentTheme = theme) }
        }
    }

    fun setAutoRefresh(enabled: Boolean) {
        viewModelScope.launch {
            context.settingsDataStore.edit { prefs ->
                prefs[booleanPreferencesKey("auto_refresh")] = enabled
            }
            _state.update { it.copy(autoRefreshEnabled = enabled) }
        }
    }

    fun setRefreshInterval(hours: Int) {
        viewModelScope.launch {
            context.settingsDataStore.edit { prefs ->
                prefs[intPreferencesKey("refresh_interval")] = hours
            }
            _state.update { it.copy(refreshIntervalHours = hours) }
        }
    }

    fun setNotificationEnabled(enabled: Boolean) {
        viewModelScope.launch {
            context.settingsDataStore.edit { prefs ->
                prefs[booleanPreferencesKey("notification_enabled")] = enabled
            }
            _state.update { it.copy(notificationEnabled = enabled) }
        }
    }

    fun showApiKeyDialog(provider: LLMProvider) {
        val existingConfig = _state.value.llmConfigs[provider]
        _state.update {
            it.copy(
                showApiKeyDialog = true,
                editingProvider = provider,
                editingApiKey = existingConfig?.apiKey ?: "",
                editingModel = existingConfig?.model ?: LLMConfig.defaultModels[provider] ?: ""
            )
        }
    }

    fun hideApiKeyDialog() {
        _state.update {
            it.copy(
                showApiKeyDialog = false,
                editingProvider = null,
                editingApiKey = "",
                editingModel = ""
            )
        }
    }

    fun updateEditingApiKey(key: String) {
        _state.update { it.copy(editingApiKey = key) }
    }

    fun updateEditingModel(model: String) {
        _state.update { it.copy(editingModel = model) }
    }

    fun saveLlmConfig() {
        val provider = _state.value.editingProvider ?: return
        val apiKey = _state.value.editingApiKey
        val model = _state.value.editingModel

        if (apiKey.isBlank()) return

        viewModelScope.launch {
            val newConfig = LLMConfig(
                provider = provider,
                apiKey = apiKey,
                model = model,
                isEnabled = true
            )

            val updatedConfigs = _state.value.llmConfigs + (provider to newConfig)

            context.settingsDataStore.edit { prefs ->
                val configsMap = updatedConfigs.mapKeys { it.key.name }
                prefs[stringPreferencesKey("llm_configs")] = json.encodeToString(configsMap)
            }

            _state.update {
                it.copy(
                    llmConfigs = updatedConfigs,
                    showApiKeyDialog = false,
                    editingProvider = null,
                    editingApiKey = "",
                    editingModel = ""
                )
            }
        }
    }

    fun removeLlmConfig(provider: LLMProvider) {
        viewModelScope.launch {
            val updatedConfigs = _state.value.llmConfigs - provider

            context.settingsDataStore.edit { prefs ->
                val configsMap = updatedConfigs.mapKeys { it.key.name }
                prefs[stringPreferencesKey("llm_configs")] = json.encodeToString(configsMap)
            }

            _state.update { it.copy(llmConfigs = updatedConfigs) }
        }
    }
